#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;  // Single thread

    uint32_t idx = 0;
    asm volatile("" : : : "memory");  // Compiler barrier before timing

    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        idx = indices[idx];  // Serial dependency chain
    }
    volatile uint64_t end = clock64();

    asm volatile("" : : : "memory");  // Compiler barrier after timing

    // Anti-optimization sink - CRITICAL: cast to 64-bit first
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");  // +l requires 64-bit operand

    *cycles = (end - start) / 10000000;  // Average cycles per access
}

int main() {
    const size_t SIZE = 32 * 1024 * 1024;  // 32M elements = 128 MB
    const uint64_t ITERATIONS = 10000000;

    // Allocate host memory for indices
    uint32_t* h_indices = (uint32_t*)malloc(SIZE * sizeof(uint32_t));

    // Initialize indices array with random permutation (Fisher-Yates shuffle)
    for (size_t i = 0; i < SIZE; i++) {
        h_indices[i] = i;
    }

    // LCG parameters for shuffle
    uint32_t seed = 12345;
    for (size_t i = SIZE - 1; i > 0; i--) {
        seed = seed * 1664525 + 1013904223;  // LCG
        uint32_t j = seed % (i + 1);
        uint32_t temp = h_indices[i];
        h_indices[i] = h_indices[j];
        h_indices[j] = temp;
    }

    // Allocate device memory
    uint32_t* d_indices;
    uint64_t* d_cycles;
    cudaMalloc(&d_indices, SIZE * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Copy indices to device
    cudaMemcpy(d_indices, h_indices, SIZE * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Run 3 trials
    uint64_t results[3];
    for (int trial = 0; trial < 3; trial++) {
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, SIZE);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        results[trial] = cycles;
    }

    // Calculate median
    std::sort(results, results + 3);
    uint64_t median_latency = results[1];

    printf("dram_latency_cycles: %lu\n", median_latency);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

#define TRIALS 3
#define MAX_WORKING_SET_MB 100
#define MIN_WORKING_SET_MB 1
#define ACCESS_COUNT 1000000

// Linear congruential generator for random permutation
__host__ uint32_t lcg_next(uint32_t& seed) {
    seed = seed * 1664525U + 1013904223U;
    return seed;
}

__global__ void measure_latency_for_size(volatile uint32_t* indices, uint64_t* results, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;

    // Warm up
    for (int i = 0; i < 1000; i++) {
        idx = indices[idx];
    }

    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint32_t i = 0; i < ACCESS_COUNT; i++) {
        idx = indices[idx];
    }

    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    results[0] = (end - start) / ACCESS_COUNT;
}

int main() {
    // Test different working set sizes
    const int num_sizes = 20;
    uint32_t sizes[num_sizes];

    // Generate logarithmic sweep from 1MB to 100MB
    for (int i = 0; i < num_sizes; i++) {
        float ratio = (float)i / (num_sizes - 1);
        sizes[i] = MIN_WORKING_SET_MB + (uint32_t)((MAX_WORKING_SET_MB - MIN_WORKING_SET_MB) * ratio * ratio);
    }

    // Allocate maximum size needed
    const size_t max_elements = (MAX_WORKING_SET_MB * 1024 * 1024) / sizeof(uint32_t);
    uint32_t* h_indices = (uint32_t*)malloc(max_elements * sizeof(uint32_t));
    uint32_t* d_indices;
    uint64_t* d_results;

    cudaMalloc(&d_indices, max_elements * sizeof(uint32_t));
    cudaMalloc(&d_results, sizeof(uint64_t));

    uint64_t latencies[TRIALS][num_sizes];

    for (int trial = 0; trial < TRIALS; trial++) {
        for (int s = 0; s < num_sizes; s++) {
            uint32_t current_size = sizes[s];
            size_t elements = (current_size * 1024 * 1024) / sizeof(uint32_t);

            // Generate random permutation
            uint32_t seed = 12345;
            for (size_t i = 0; i < elements; i++) {
                h_indices[i] = i;
            }

            // Fisher-Yates shuffle
            for (size_t i = elements - 1; i > 0; i--) {
                uint32_t j = lcg_next(seed) % (i + 1);
                uint32_t temp = h_indices[i];
                h_indices[i] = h_indices[j];
                h_indices[j] = temp;
            }

            // Convert to pointer chasing array
            for (size_t i = 0; i < elements; i++) {
                h_indices[i] = h_indices[i];
            }

            cudaMemcpy(d_indices, h_indices, elements * sizeof(uint32_t), cudaMemcpyHostToDevice);

            measure_latency_for_size<<<1, 1>>>(d_indices, d_results, elements);
            cudaDeviceSynchronize();

            uint64_t result;
            cudaMemcpy(&result, d_results, sizeof(uint64_t), cudaMemcpyDeviceToHost);
            latencies[trial][s] = result;
        }
    }

    // Find cache cliff
    uint64_t median_latencies[num_sizes];
    for (int s = 0; s < num_sizes; s++) {
        uint64_t trial_results[TRIALS];
        for (int t = 0; t < TRIALS; t++) {
            trial_results[t] = latencies[t][s];
        }
        std::sort(trial_results, trial_results + TRIALS);
        median_latencies[s] = trial_results[TRIALS / 2];
    }

    // Find the cliff - where latency increases by > 50%
    uint32_t l2_size_mb = MIN_WORKING_SET_MB;
    for (int s = 1; s < num_sizes; s++) {
        if (median_latencies[s] > median_latencies[s-1] * 1.5) {
            l2_size_mb = sizes[s-1];
            break;
        }
    }

    printf("l2_cache_size_mb: %u\n", l2_size_mb);

    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_results);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_boost_clock(uint64_t* cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    volatile uint64_t start = clock64();

    // Compute-intensive loop to trigger boost behavior
    float sum = 0.0f;
    #pragma unroll 1
    for (uint64_t i = 0; i < 100000000ULL; i++) {
        sum += i * 0.1f;
        sum *= 1.000001f;
    }

    volatile uint64_t end = clock64();

    // Prevent optimization
    volatile uint64_t sink64 = (uint64_t)sum;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = end - start;
}

int main() {
    uint64_t* d_cycles;
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    // Warm up
    measure_boost_clock<<<1, 1>>>(d_cycles);
    cudaDeviceSynchronize();

    // Measure wall-clock time
    cudaEventRecord(start_event);
    measure_boost_clock<<<1, 1>>>(d_cycles);
    cudaEventRecord(stop_event);
    cudaEventSynchronize(stop_event);

    float elapsed_ms;
    cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);

    uint64_t gpu_cycles;
    cudaMemcpy(&gpu_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

    // Calculate frequency in MHz
    double elapsed_seconds = elapsed_ms / 1000.0;
    double frequency_mhz = (gpu_cycles / elapsed_seconds) / 1000000.0;

    printf("actual_boost_clock_mhz: %.0f\n", frequency_mhz);

    cudaFree(d_cycles);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    return 0;
}
